- (instancetype)init {
    self = [super init];
    if (self) {
        _queue = dispatch_queue_create("__eventqueue", NULL);
        dispatch_queue_set_specific(_queue, kWBEventManagerQueueSpecificKey, (void *)kWBEventManagerQueueSpecificKey, NULL);
        _eventList = [[NSMutableArray alloc] init];
        _lastReportTime = 0;
        _vappUsedTimeInSecond = 0;
        _appUsedTimeInSecond = 0;
        _backgroundUsedTimeInSecond = 0;
        _pendingVappId = 0;
        _lastUsageRecordTime = CFAbsoluteTimeGetCurrent();
        _enabled = FALSE;
        [self loadUsageState];
        dispatch_async([self queue], ^{
            [self processEventList];
            [self vappUsageRecord];
        });
        [self load];
    }
    return self;
}

- (void)load {
    NSString *filePath = [[WBStorageManager sharedManager].docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kEventCacheFile]];
    if (![NSFileManager.defaultManager fileExistsAtPath:filePath]) {
        return;
    }
    NSError *error = nil;
    NSData *data = [NSData dataWithContentsOfFile:filePath options:0 error:&error];
    if (error || !data) {
        return;
    }
    id json = [NSJSONSerialization JSONObjectWithData:data options:0 error:&error];
    if (error || ![json isKindOfClass:[NSArray class]]) {
        return;
    }
    NSArray *entries = (NSArray *)json;
    NSMutableArray<WBEvent *> *events = [NSMutableArray arrayWithCapacity:entries.count];
    for (id item in entries) {
        if (![item isKindOfClass:[NSDictionary class]]) {
            continue;
        }
        NSDictionary *entry = (NSDictionary *)item;
        NSNumber *typeNum = entry[@"n"];
        NSNumber *timeNum = entry[@"t"];
        id paramsObj = entry[@"d"];
        if (!typeNum || ![typeNum isKindOfClass:[NSNumber class]]) {
            continue;
        }
        WBEvent *event = [[WBEvent alloc] initWithType:typeNum.integerValue data:[paramsObj isKindOfClass:[NSDictionary class]] ? paramsObj : nil];
        if ([timeNum isKindOfClass:[NSNumber class]]) {
            event.time = timeNum.doubleValue;
        }
        event.status = eventStatusAwaitReport;
        event.urgent = NO;
        [events addObject:event];
    }
    if (events.count > 0) {
        dispatch_async([self queue], ^{
            [[self eventList] addObjectsFromArray:events];
        });
    }
    [NSFileManager.defaultManager removeItemAtPath:filePath error:nil];
}

/// 冷启动时恢复上一次尚未随 heartbeat 上报的 a/v/bg 数据。
- (void)loadUsageState {
    // 恢复未上报的 heartbeat 累计值，保证热启动和冷启动后还能继续累计真实时长。
    self.appUsedTimeInSecond = [WBEventManager persistedPendingAppDuration];
    self.vappUsedTimeInSecond = [WBEventManager persistedPendingVappDuration];
    self.backgroundUsedTimeInSecond = [WBEventManager persistedPendingBackgroundDuration];
    self.pendingVappId = [WBEventManager persistedPendingVappId];
    self.lastUsageRecordTime = CFAbsoluteTimeGetCurrent();
    if ([WBEventManager hasBackgroundEnterTime]) {
        // 进到这里说明上一个进程已经结束，残留的后台时间点已经不可信，直接丢弃。
        [WBEventManager clearBackgroundTrackingState];
    }
}

/// 将当前未上报的累计时长同步到本地，避免进程结束后丢失。
- (void)persistUsageState {
    [WBEventManager setDefaultsObject:(self.appUsedTimeInSecond > 0 ? @(self.appUsedTimeInSecond) : nil) forKey:kEventPendingAppDurationKey];
    [WBEventManager setDefaultsObject:(self.vappUsedTimeInSecond > 0 ? @(self.vappUsedTimeInSecond) : nil) forKey:kEventPendingVappDurationKey];
    [WBEventManager setDefaultsObject:(self.backgroundUsedTimeInSecond > 0 ? @(self.backgroundUsedTimeInSecond) : nil) forKey:kEventPendingBackgroundDurationKey];
    [WBEventManager setDefaultsObject:(self.pendingVappId != 0 ? @(self.pendingVappId) : nil) forKey:kEventPendingVappIdKey];
}

/// 将内部用的浮点秒数转换为上报给服务端的整秒值。
- (uint32_t)wholeSecondsFromDuration:(NSTimeInterval)duration {
    if (duration <= 0) {
        return 0;
    }
    return (uint32_t)duration;
}

/// 获取当前正在运行的 vapp id，没有则返回 0。
- (NSInteger)currentRunningVappId {
    return [WBVAppManager sharedManager].runningVApp.vid;
}

/// 生成一份操作追踪文件使用的 usage 快照，保证每条记录都带完整的三段时长。
- (NSDictionary<NSString *, NSNumber *> *)operationTraceUsageSnapshotInternal {
    return @{
        @"appUsedTimeInSecond": @([self wholeSecondsFromDuration:self.appUsedTimeInSecond]),
        @"vappUsedTimeInSecond": @([self wholeSecondsFromDuration:self.vappUsedTimeInSecond]),
        @"backgroundUsedTimeInSecond": @([self wholeSecondsFromDuration:self.backgroundUsedTimeInSecond]),
    };
}

/// 合并待上报时长对应的 vapp id；如果一轮内混入多个 vapp，则清成冲突态避免归错。
- (void)mergePendingVappId:(NSInteger)vappId {
    if (vappId <= 0) {
        return;
    }
    if (self.pendingVappId == 0) {
        self.pendingVappId = vappId;
        return;
    }
    if (self.pendingVappId > 0 && self.pendingVappId != vappId) {
        self.pendingVappId = -1;
    }
}

/// 结算最近一个前台可观测区间的真实时长，并累计到 a/v。
- (void)accumulateElapsedUsageAtTime:(CFAbsoluteTime)now {
    if (self.lastUsageRecordTime <= 0) {
        self.lastUsageRecordTime = now;
        return;
    }
    // 后台区间会在回前台或终止时统一补算，这里直接跳过，避免重复累计。
    if ([WBEventManager hasBackgroundEnterTime]) {
        self.lastUsageRecordTime = now;
        return;
    }
    CFAbsoluteTime elapsed = now - self.lastUsageRecordTime;
    if (elapsed <= 0) {
        self.lastUsageRecordTime = now;
        return;
    }
    self.appUsedTimeInSecond += elapsed;
    NSInteger currentVappId = [self currentRunningVappId];
    if (currentVappId > 0) {
        [self mergePendingVappId:currentVappId];
        self.vappUsedTimeInSecond += elapsed;
    }
    self.lastUsageRecordTime = now;
}

/// 用进入后台和恢复时的时间点，补算挂起期间的真实时长，并并入下一次 heartbeat。
- (void)applyBackgroundUsageAtTime:(CFAbsoluteTime)now {
    if (![WBEventManager hasBackgroundEnterTime]) {
        self.lastUsageRecordTime = now;
        return;
    }
    // 根据生命周期时间点重建后台挂起区间，并将其并入下一次 heartbeat。
    CFAbsoluteTime backgroundTime = [WBEventManager backgroundEnterTime];
    if (backgroundTime > 0 && now >= backgroundTime) {
        NSTimeInterval backgroundDuration = now - backgroundTime;
        self.appUsedTimeInSecond += backgroundDuration;
        self.backgroundUsedTimeInSecond += backgroundDuration;
        // 只有进入后台时确实有 vapp 在跑，才把后台区间同时累计进 v。
        if ([WBEventManager backgroundHadRunningVapp]) {
            NSInteger backgroundVappId = [WBEventManager backgroundVappId];
            [self mergePendingVappId:backgroundVappId];
            self.vappUsedTimeInSecond += backgroundDuration;
        }
    }
    [WBEventManager clearBackgroundTrackingState];
    self.lastUsageRecordTime = now;
}

/// 判断当前累计的真实时长是否已经达到 heartbeat 阈值。
- (BOOL)shouldReportHeartbeat {
    return (self.appUsedTimeInSecond >= self.heartbeatInterval || self.vappUsedTimeInSecond >= self.heartbeatInterval);
}

/// 在需要时立即触发一次 heartbeat，否则仅同步当前累计状态。
- (void)reportHeartbeatIfNeeded {
    uint32_t h = self.heartbeatInterval;
    NSTimeInterval app = self.appUsedTimeInSecond;
    NSTimeInterval vapp = self.vappUsedTimeInSecond;
    if ([self shouldReportHeartbeat]) {
        [self doHeartBeatWithUsageReport];
        [self doProcessEventList];
        return;
    }
    [self persistUsageState];
}

- (void)save {
    __block NSArray<WBEvent *> *snapshot = nil;
    dispatch_sync([self queue], ^{
        snapshot = [[self eventList] copy];
    });
    NSString *filePath = [[WBStorageManager sharedManager].docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kEventCacheFile]];
    if (snapshot.count == 0) {
        if ([NSFileManager.defaultManager fileExistsAtPath:filePath]) {
            [NSFileManager.defaultManager removeItemAtPath:filePath error:nil];
        }
        return;
    }
    NSMutableArray *entries = [NSMutableArray arrayWithCapacity:snapshot.count];
    for (WBEvent *event in snapshot) {
        NSMutableDictionary *dict = [NSMutableDictionary dictionary];
        dict[@"t"] = @(event.time);
        dict[@"n"] = @(event.type);
        if (event.params) {
            dict[@"d"] = event.params;
        }
        [entries addObject:dict];
    }
    NSError *error = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:entries options:0 error:&error];
    if (error || !data) {
        return;
    }
    NSURL *fileURL = [NSURL fileURLWithPath:filePath];
    BOOL ok = [data writeToURL:fileURL options:NSDataWritingAtomic error:&error];
    if (!ok) {
